async (params, browser) => {
  // Open place page
  await browser.open(`${params.place_url}`)

  // Wait for reviews section to load
  await browser.waitForSelector('[data-test-target=\'HR_CC_CARD\'], [data-test-target=\'review-card\'], .review-container, [class*=\'ReviewCard\'], #REVIEWS', 15000)

  // Let reviews render
  await browser.wait(3000)

  // Scroll to reviews section
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll to load more reviews
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll further for more reviews
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Extract reviews
  const result = await browser.evaluate(`const placeNameEl = document.querySelector('h1#HEADING, h1[data-test-target="top-info-header"]'); const placeName = placeNameEl ? placeNameEl.textContent.trim() : ''; const reviews = []; const reviewEls = document.querySelectorAll('[data-test-target="HR_CC_CARD"], [data-test-target="review-card"], .review-container, [class*="ReviewCard"], [class*="reviewCard"]'); for (let i = 0; i < Math.min(reviewEls.length, 15); i++) { const el = reviewEls[i]; const reviewerEl = el.querySelector('[class*="username"], [class*="memberOverlay"] a, [class*="reviewer"] a, a[class*="ui_header_link"], [class*="member"] a span'); const reviewer = reviewerEl ? reviewerEl.textContent.trim() : ''; const ratingEl = el.querySelector('svg[aria-label*="bubble"], .ui_bubble_rating, [class*="ratingValue"], span[class*="rating"]'); const rating = ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.className || '') : ''; const titleEl = el.querySelector('[data-test-target="review-title"], a[class*="title"], .noQuotes, span[class*="reviewTitle"], [class*="title"] span'); const title = titleEl ? titleEl.textContent.trim() : ''; const textEl = el.querySelector('[data-test-target="review-body"], .entry, [class*="reviewText"], q span, [class*="reviewBody"]'); const text = textEl ? textEl.textContent.trim().substring(0, 500) : ''; const dateEl = el.querySelector('[class*="date"], .ratingDate, [class*="Date"], span[class*="date"]'); const date = dateEl ? (dateEl.getAttribute('title') || dateEl.textContent.trim()) : ''; const tripTypeEl = el.querySelector('[class*="tripType"], [class*="trip"], .recommend-titleInline'); const tripType = tripTypeEl ? tripTypeEl.textContent.trim() : ''; const contributionEl = el.querySelector('[class*="contribution"], [class*="memberBadge"]'); const contributions = contributionEl ? contributionEl.textContent.trim() : ''; if (title || text) { reviews.push({ reviewer: reviewer, rating: rating, title: title, text: text, date: date, trip_type: tripType, contributions: contributions }); } } return { place_name: placeName, review_count: reviews.length, reviews: reviews, url: window.location.href }`)

  return result
}
